import { useState } from 'react';
import api from '../services/api';

const TaskForm = ({ onTaskCreated }) => {
  const [title, setTitle] = useState('');
  const [deadline, setDeadline] = useState('');
  const [assignedTo, setAssignedTo] = useState(''); // Member ki User ID

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // Backend ko data bhejo
      await api.post('/tasks', { 
        title, 
        deadline, 
        assignedTo, 
        project: 'General Project' 
      });
      
      alert('Task Assign Ho Gaya!');
      setTitle('');
      setDeadline('');
      setAssignedTo('');
      
      if (onTaskCreated) onTaskCreated(); // Dashboard list refresh karne ke liye
    } catch (err) {
      console.error(err);
      alert('Task banane mein error aaya. User ID sahi daali hai?');
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '10px', maxWidth: '300px' }}>
      <input 
        type="text" 
        placeholder="Task Title" 
        value={title} 
        onChange={(e) => setTitle(e.target.value)} 
        required 
      />
      <input 
        type="date" 
        value={deadline} 
        onChange={(e) => setDeadline(e.target.value)} 
        required 
      />
      <input 
        type="text" 
        placeholder="Assign to (User ID)" 
        value={assignedTo} 
        onChange={(e) => setAssignedTo(e.target.value)} 
        required 
      />
      <button type="submit" style={{ background: '#007bff', color: 'white', border: 'none', padding: '10px', borderRadius: '5px', cursor: 'pointer' }}>
        Create Task
      </button>
    </form>
  );
};

export default TaskForm;
